#!/usr/bin/env node
const { spawnSync, execSync } = require('child_process')
const fs = require('fs')
const path = require('path')

try {
  const envPath = process.env.ENV_FILE || '../../env.json'
  if (path.isAbsolute(envPath)) {
    process.env = Object.assign({}, process.env, require(envPath))
  } else {
    process.env = Object.assign({}, process.env, require(path.resolve(__dirname, envPath)))
  }
} catch {
  process.env = Object.assign({ PORT: '8080' }, process.env)
}

const {
  BITCOIN_DATADIR,
  BITCOIN_RPCUSER,
  BITCOIN_RPCPASSWORD,
  BITCOIN_RPCPORT,
  BITCOIN_CLI_BIN
} = process.env

const BITCOIN_CLI = BITCOIN_CLI_BIN || '/usr/local/bin/bitcoin-cli'

const sleep = (ms) => new Promise(r => setTimeout(r, ms))

function run(cmd, opts = {}) {
  try {
    return execSync(cmd, { stdio: 'pipe', encoding: 'utf8', ...opts }).trim()
  } catch (e) {
    if (!opts.ignoreError) {
      console.error(`❌ Command failed: ${cmd}`)
      console.error(e.stderr?.toString() || e.message)
      throw e
    }
    return e.stderr?.toString() || e.message || ''
  }
}

async function waitForBitcoinRPC() {
  console.log('Waiting for RPC to be ready... (This can take a moment)');
  let attempts = 0;

  while (true) {
    const res = spawnSync(BITCOIN_CLI, [
      '-regtest',
      `-rpcuser=${BITCOIN_RPCUSER}`,
      `-rpcpassword=${BITCOIN_RPCPASSWORD}`,
      `-rpcport=${BITCOIN_RPCPORT}`,
      'getblockchaininfo'
    ]);

    if (res.status === 0) {
      console.log('RPC check successful.');
      break;
    }

    await sleep(500);
    attempts++;

    if (attempts <= 5 || attempts % 20 === 0) {
      console.log(`RPC check attempt ${attempts} failed...`);
      if (res.stderr && res.stderr.toString()) {
        const errorMsg = res.stderr.toString().trim();
        console.error(`Error: ${errorMsg}`);
        if (errorMsg.includes("error code: -28")) {
          console.log("(This is normal, bitcoind is still warming up.)");
        }
      } else if (res.error) {
        console.error(`Spawn Error: ${res.error.message}`);
        if (res.error.code === 'ENOENT') {
          console.log(`(Could not find executable: ${BITCOIN_CLI}. Check your BITCOIN_CLI_BIN in env.json)`);
        }
      }
    }
  }
}

function setupWalletAndMine() {
  const WALLET = 'regtestwallet'
  console.log('Checking wallet status...')

  // Helper to parse JSON output safely
  const runJson = (cmd, opts = {}) => {
    try {
      const out = run(cmd, opts)
      return out ? JSON.parse(out) : null
    } catch (e) {
      console.log(`⚠️ Failed to parse JSON from cmd: ${cmd}. Output: ${e.message}`)
      return null
    }
  }

  const loadedWallets = runJson(
    `${BITCOIN_CLI} -regtest \
    -rpcuser="${BITCOIN_RPCUSER}" \
    -rpcpassword="${BITCOIN_RPCPASSWORD}" \
    -rpcport=${BITCOIN_RPCPORT} listwallets`,
    { ignoreError: true }
  ) || []

  if (loadedWallets.includes(WALLET)) {
    console.log(`✅ Wallet '${WALLET}' is already loaded.`)
  } else {
    // Check if wallet exists on disk
    const walletDirData = runJson(
      `${BITCOIN_CLI} -regtest \
      -rpcuser="${BITCOIN_RPCUSER}" \
      -rpcpassword="${BITCOIN_RPCPASSWORD}" \
      -rpcport=${BITCOIN_RPCPORT} listwalletdir`,
      { ignoreError: true }
    )

    // listwalletdir returns { wallets: [ { name: ... } ] }
    const existingWallets = (walletDirData && walletDirData.wallets)
      ? walletDirData.wallets.map(w => w.name)
      : []

    if (existingWallets.includes(WALLET)) {
      console.log(`found existing wallet '${WALLET}' on disk. Loading...`)
      run(
        `${BITCOIN_CLI} -regtest \
        -rpcuser="${BITCOIN_RPCUSER}" \
        -rpcpassword="${BITCOIN_RPCPASSWORD}" \
        -rpcport=${BITCOIN_RPCPORT} loadwallet "${WALLET}"`,
        { ignoreError: true }
      )
      console.log(`✅ Loaded wallet '${WALLET}'.`)
    } else {
      console.log(`Creating NEW wallet '${WALLET}'...`)
      run(
        `${BITCOIN_CLI} -regtest \
        -rpcuser="${BITCOIN_RPCUSER}" \
        -rpcpassword="${BITCOIN_RPCPASSWORD}" \
        -rpcport=${BITCOIN_RPCPORT} createwallet "${WALLET}"`,
        { ignoreError: true }
      )
      console.log(`✅ Created wallet '${WALLET}'.`)
    }
  }

  // Helper to check for existing blocks data on disk
  const blocksPath = path.join(BITCOIN_DATADIR, 'regtest', 'blocks')
  if (fs.existsSync(blocksPath)) {
    console.log(`[DEBUG] Persistence Check: Blocks directory FOUND at ${blocksPath}`)
    const files = fs.readdirSync(blocksPath)
    console.log(`[DEBUG] Blocks dir content count: ${files.length}`)
  } else {
    console.log(`[DEBUG] Persistence Check: Blocks directory NOT FOUND at ${blocksPath} (Expected for fresh install)`)
  }

  const newAddr = run(
    `${BITCOIN_CLI} -regtest \
    -rpcuser="${BITCOIN_RPCUSER}" \
    -rpcpassword="${BITCOIN_RPCPASSWORD}" \
    -rpcport=${BITCOIN_RPCPORT} \
    -rpcwallet="${WALLET}" getnewaddress`
  )

  // Retry getblockcount a few times in case bitcoind is still loading indices
  let blockCount = 0
  for (let i = 0; i < 3; i++) {
    const rawCount = run(
      `${BITCOIN_CLI} -regtest \
      -rpcuser="${BITCOIN_RPCUSER}" \
      -rpcpassword="${BITCOIN_RPCPASSWORD}" \
      -rpcport=${BITCOIN_RPCPORT} getblockcount`,
      { ignoreError: true }
    )
    console.log(`[DEBUG] Attempt ${i + 1}/3: getblockcount raw output: '${rawCount}'`)

    // Parse
    try {
      blockCount = parseInt(rawCount.trim())
      if (isNaN(blockCount)) blockCount = 0
    } catch { blockCount = 0 }

    if (blockCount > 0) break

    // If we have wallets but blockCount is 0, give it a moment
    if (blockCount === 0) {
      console.log('... block count is 0, waiting 2s ...')
      spawnSync('sleep', ['2'])
    }
  }

  if (blockCount < 101) {
    console.log(`Current block count: ${blockCount}. Mining ${101 - blockCount} blocks to ${newAddr} ...`)
    run(
      `${BITCOIN_CLI} -regtest \
      -rpcuser="${BITCOIN_RPCUSER}" \
      -rpcpassword="${BITCOIN_RPCPASSWORD}" \
      -rpcport=${BITCOIN_RPCPORT} \
      -rpcwallet="${WALLET}" generatetoaddress ${101 - blockCount} "${newAddr}"`,
      { ignoreError: true }
    )
    console.log('✅ Wallet ready and blocks mined.')
  } else {
    console.log(`⚡️ Chain state preserved (Height: ${blockCount}). Skipping initial mining.`)
  }
}


module.exports = {
  async start() {
    console.log('=== Starting Bitcoin Regtest ===')
    if (!fs.existsSync(BITCOIN_DATADIR)) {
      console.log(`⚠️ Creating Bitcoin data dir: ${BITCOIN_DATADIR}`)
      fs.mkdirSync(BITCOIN_DATADIR, { recursive: true })
    }
    const running = spawnSync('pgrep', ['-x', 'bitcoind'])
    if (running.status !== 0) {
      run(
        `bitcoind -regtest -daemon \
        -datadir="${BITCOIN_DATADIR}" \
        -rpcuser="${BITCOIN_RPCUSER}" \
        -rpcpassword="${BITCOIN_RPCPASSWORD}" \
        -rpcallowip=127.0.0.1 \
        -rpcport=${BITCOIN_RPCPORT} \
        -fallbackfee=0.0002`
      )
    }
    console.log('✅ bitcoind launched, waiting for readiness...')
    await waitForBitcoinRPC()
    console.log('✅ bitcoind RPC ready.')

    setupWalletAndMine()

    console.log('✅ bitcoind is fully set up and ready.')
  },

  async stop() {
    console.log('Stopping bitcoind...')
    try {
      run(
        `${BITCOIN_CLI} -regtest \
        -rpcuser="${BITCOIN_RPCUSER}" \
        -rpcpassword="${BITCOIN_RPCPASSWORD}" \
        -rpcport=${BITCOIN_RPCPORT} stop`,
        { ignoreError: true }
      )
      console.log('🛑 bitcoind stop requested. Waiting for process to exit...')

      // Wait for process to exit (max 30s)
      for (let i = 0; i < 30; i++) {
        const running = spawnSync('pgrep', ['-x', 'bitcoind'])
        if (running.status !== 0) {
          console.log('✅ bitcoind has stopped.')
          return
        }
        await new Promise(r => setTimeout(r, 1000))
      }
      console.log('⚠️ bitcoind did not stop in time (30s).')
    } catch {
      console.log('⚠️ bitcoind may not be running.')
    }
  },

  async reset() {
    console.log('🗑️  Resetting Bitcoin data by removing ' + BITCOIN_DATADIR)
    if (fs.existsSync(BITCOIN_DATADIR)) {
      fs.rmSync(BITCOIN_DATADIR, { recursive: true, force: true })
    }
    console.log('✅ Bitcoin data removed.')
  }
}